// Placeholder: replace with real RL policy after training (load model, obs = offer features, action = include 0/1).
// Goal: from ~200_000 offers select the best 200.
// Observation: offer features (e.g. price norm, duration, stops, airline); action: keep/discard or score.
const TOP_K = 200;
const input = msg.payload || {};
const data = input.data || [];
const meta = input.meta || {};
let selected = data;
if (data.length > TOP_K) {
  // Scaffold: take first TOP_K; in production the trained agent would score/select best TOP_K.
  selected = data.slice(0, TOP_K);
}
flow.set('filter_selected', selected);
msg.payload = { meta, data: selected, totalInput: data.length, totalOutput: selected.length };
return msg;

// Compare the deployed RLAgent selection to a simple oracle heuristic.
// This does NOT implement /step; it just adds diagnostics to the /filter response.
// Heuristic: lower mean price is better; bonus if output count near TOP_K.
const input = msg.payload || {};
const meta = input.meta || {};
const selected = Array.isArray(input.data) ? input.data : [];
const TOP_K = 200;

function getPrice(x) {
  if (!x) return null;
  const p = x.price ?? x.totalPrice ?? x.total_price ?? x.fare;
  if (typeof p === 'number') return p;
  const n = Number(p);
  return Number.isFinite(n) ? n : null;
}

let meanPrice = null;
if (selected.length > 0) {
  const ps = selected.map(getPrice).filter(p => typeof p === 'number');
  if (ps.length > 0) meanPrice = ps.reduce((s, v) => s + v, 0) / ps.length;
}

let oracleScore = 0;
if (meanPrice != null) oracleScore += -meanPrice;
if (selected.length >= TOP_K - 10 && selected.length <= TOP_K + 10) oracleScore += 1000;

meta.oracle_eval = {
  score: oracleScore,
  mean_price: meanPrice,
  selected_count: selected.length,
  target_count: TOP_K,
};

msg.payload = { ...input, meta };
return msg;

