// RLOracle (step API) for RL training: reset -> obs; step(action) -> obs, reward, done.
// Observation: 4 dims [price_norm, duration_norm, stops_norm, index_norm]. Action: 1 dim (include if > 0.5).
// IMPORTANT: /filter primes the next episode dataset by storing offers in flow.oracle_offers_input.
const NUM_OFFERS = 100;
const TARGET_SELECT = 20;
const PRICE_SCALE = 500;
const DURATION_SCALE = 10;
const STOPS_SCALE = 3;

function makeOffers(n) {
  const out = [];
  for (let i = 0; i < n; i++) {
    out.push({
      price: 80 + Math.random() * 400,
      duration: 0.5 + Math.random() * 8,
      stops: Math.floor(Math.random() * 4)
    });
  }
  return out;
}

function toOffer(x) {
  if (!x || typeof x !== 'object') return null;
  const price = (typeof x.price === 'number') ? x.price : Number(x.price ?? x.totalPrice ?? x.total_price ?? x.fare);
  const duration = (typeof x.duration === 'number') ? x.duration : Number(x.duration);
  const stops = (typeof x.stops === 'number') ? x.stops : Number(x.stops);
  if (!Number.isFinite(price) || !Number.isFinite(duration) || !Number.isFinite(stops)) return null;
  return { price, duration, stops };
}

function features(o, idx, n) {
  return [
    o.price / PRICE_SCALE,
    o.duration / DURATION_SCALE,
    o.stops / STOPS_SCALE,
    idx / (n || NUM_OFFERS)
  ];
}

const payload = msg.payload || {};
let offers = flow.get('oracle_offers');
let index = flow.get('oracle_index');
let selected = flow.get('oracle_selected');

if (payload.reset) {
  // Prefer the most recently ingested real offers from /filter
  const ingested = flow.get('oracle_offers_input');
  const realOffers = Array.isArray(ingested) ? ingested.map(toOffer).filter(x => x) : [];
  offers = realOffers.length > 0 ? realOffers : makeOffers(NUM_OFFERS);
  flow.set('oracle_offers', offers);
  flow.set('oracle_index', 0);
  flow.set('oracle_selected', []);
  const obs = features(offers[0], 0, offers.length);
  msg.payload = { observation: obs, observation_names: ["price_norm","duration_norm","stops_norm","index_norm"], action_names: ["include"], reward: 0, done: false };
  msg.headers = { 'Content-Type': 'application/json' };
  return msg;
}

const action = Array.isArray(payload.action) ? payload.action[0] : 0;
if (index == null) index = 0;
if (selected == null) selected = [];
if (!Array.isArray(offers) || offers.length === 0) {
  offers = makeOffers(NUM_OFFERS);
  flow.set('oracle_offers', offers);
}

if (action > 0.5) selected.push(index);
index += 1;
flow.set('oracle_index', index);
flow.set('oracle_selected', selected);

if (index >= offers.length) {
  let reward = 0;
  if (selected.length > 0) {
    const meanPrice = selected.reduce((s, i) => s + offers[i].price, 0) / selected.length;
    reward = -meanPrice / PRICE_SCALE;
    if (selected.length >= TARGET_SELECT - 2 && selected.length <= TARGET_SELECT + 2) reward += 2;
  }
  msg.payload = { observation: [0, 0, 0, 0], reward, done: true };
} else {
  const obs = features(offers[index], index, offers.length);
  msg.payload = { observation: obs, reward: 0, done: false };
}
msg.headers = { 'Content-Type': 'application/json' };
return msg;
